use ndarray::{Array1, Array2, ArrayView1, ArrayView2};

/// Type alias for a 1D array (vector) of floating point values
pub type Vector = Array1<f64>;

/// Type alias for a 2D array (matrix) of floating point values
pub type Matrix = Array2<f64>;

/// Type alias for a read-only view of a 1D array
pub type VectorView<'a> = ArrayView1<'a, f64>;

/// Type alias for a read-only view of a 2D array
pub type MatrixView<'a> = ArrayView2<'a, f64>;

/// Type alias for column indices
pub type ColIndex = Vec<usize>;

/// Type alias for row indices  
pub type RowIndex = Vec<usize>;

/// Represents the shape of a matrix (rows, columns)
pub type Shape = (usize, usize);

/// Component index type
pub type Component = usize;

/// Number of components
pub type NComponents = usize;

/// Represents a range of indices for block operations
#[derive(Debug, Clone, PartialEq)]
pub struct IndexRange {
    pub start: usize,
    pub end: usize,
}

impl IndexRange {
    /// Create a new index range
    pub fn new(start: usize, end: usize) -> Self {
        assert!(start <= end, "Start index must be <= end index");
        Self { start, end }
    }

    /// Get the length of the range
    pub fn len(&self) -> usize {
        self.end - self.start
    }

    /// Check if the range is empty
    pub fn is_empty(&self) -> bool {
        self.start == self.end
    }

    /// Convert to a standard Range
    pub fn to_range(&self) -> std::ops::Range<usize> {
        self.start..self.end
    }
}

/// Tolerance for numerical comparisons
pub const EPSILON: f64 = 1e-10;

/// Default tolerance for convergence tests
pub const DEFAULT_TOL: f64 = 1e-6;

/// Maximum iterations for iterative algorithms
pub const MAX_ITER: usize = 1000;

#[cfg(test)]
mod tests {
    use super::*;
    use ndarray::array;

    #[test]
    fn test_type_aliases() {
        let v: Vector = array![1.0, 2.0, 3.0];
        assert_eq!(v.len(), 3);

        let m: Matrix = array![[1.0, 2.0], [3.0, 4.0]];
        assert_eq!(m.shape(), &[2, 2]);
    }

    #[test]
    fn test_index_range() {
        let range = IndexRange::new(5, 10);
        assert_eq!(range.len(), 5);
        assert!(!range.is_empty());

        let empty_range = IndexRange::new(5, 5);
        assert_eq!(empty_range.len(), 0);
        assert!(empty_range.is_empty());
    }

    #[test]
    #[should_panic(expected = "Start index must be <= end index")]
    fn test_invalid_index_range() {
        IndexRange::new(10, 5);
    }
}

