use log::{debug, error, info, trace, warn};
use std::sync::Once;

static INIT: Once = Once::new();

/// Initialize the logging system with a default configuration
/// 
/// This should be called once at the start of your application.
/// Subsequent calls will be ignored.
/// 
/// The logging level can be controlled via the RUST_LOG environment variable:
/// - `RUST_LOG=debug` for debug level
/// - `RUST_LOG=multivarious=debug` for debug level only for this crate
/// - `RUST_LOG=info` for info level (default)
pub fn init_logger() {
    INIT.call_once(|| {
        env_logger::builder()
            .format_timestamp_millis()
            .init();
    });
}

/// Initialize the logging system with a custom filter
pub fn init_logger_with_filter(filter: &str) {
    INIT.call_once(|| {
        env_logger::builder()
            .parse_filters(filter)
            .format_timestamp_millis()
            .init();
    });
}

/// Log the start of a major operation
#[macro_export]
macro_rules! log_operation_start {
    ($operation:expr) => {
        log::info!("Starting operation: {}", $operation);
        log::debug!("Operation details: {} at {}:{}", $operation, file!(), line!());
    };
}

/// Log the successful completion of an operation
#[macro_export]
macro_rules! log_operation_complete {
    ($operation:expr) => {
        log::info!("Completed operation: {}", $operation);
    };
    ($operation:expr, $duration:expr) => {
        log::info!("Completed operation: {} in {:?}", $operation, $duration);
    };
}

/// Log algorithm parameters
#[macro_export]
macro_rules! log_parameters {
    ($($param:ident = $value:expr),+) => {
        log::debug!(concat!("Parameters: ", $(stringify!($param), " = {:?}, "),+), $($value),+);
    };
}

/// Log matrix dimensions
pub fn log_matrix_info(name: &str, shape: (usize, usize)) {
    debug!("Matrix '{}' shape: {} × {}", name, shape.0, shape.1);
}

/// Log convergence information
pub fn log_convergence(iteration: usize, error: f64, tolerance: f64) {
    trace!("Iteration {}: error = {:.6e}, tolerance = {:.6e}", iteration, error, tolerance);
}

/// Log a warning about numerical issues
pub fn log_numerical_warning(context: &str, details: &str) {
    warn!("Numerical warning in {}: {}", context, details);
}

/// Log memory usage estimate
pub fn log_memory_estimate(operation: &str, bytes: usize) {
    let mb = bytes as f64 / (1024.0 * 1024.0);
    debug!("Memory estimate for {}: {:.2} MB", operation, mb);
}

/// Performance logging helper
pub struct PerfLogger {
    operation: String,
    start: std::time::Instant,
}

impl PerfLogger {
    pub fn new(operation: &str) -> Self {
        info!("Starting: {}", operation);
        Self {
            operation: operation.to_string(),
            start: std::time::Instant::now(),
        }
    }
}

impl Drop for PerfLogger {
    fn drop(&mut self) {
        let duration = self.start.elapsed();
        info!("Completed: {} in {:?}", self.operation, duration);
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_logger_initialization() {
        // This test just ensures the logger can be initialized without panic
        init_logger();
        info!("Test log message");
    }

    #[test]
    fn test_log_macros() {
        init_logger();

        log_operation_start!("test operation");
        log_operation_complete!("test operation");

        let duration = std::time::Duration::from_millis(100);
        log_operation_complete!("test operation", duration);

        let n_components = 5;
        let tolerance = 1e-6;
        log_parameters!(n_components = n_components, tolerance = tolerance);
    }

    #[test]
    fn test_perf_logger() {
        init_logger();

        {
            let _perf = PerfLogger::new("test computation");
            std::thread::sleep(std::time::Duration::from_millis(10));
            // PerfLogger will log completion time when dropped
        }
    }
}

