use ndarray::{Array1, Array2, s};
use crate::common_types::{Matrix, Vector};
use approx::AbsDiffEq;

/// Generate a simple test matrix with predictable values
/// Creates an m×n matrix where element (i,j) = i*n + j + 1
pub fn test_matrix(m: usize, n: usize) -> Matrix {
    Array2::from_shape_fn((m, n), |(i, j)| (i * n + j + 1) as f64)
}

/// Generate a symmetric positive definite matrix for testing
/// Uses A^T * A + epsilon * I to ensure positive definiteness
pub fn test_symmetric_positive_definite(n: usize) -> Matrix {
    let a = test_matrix(n, n);
    let ata = a.t().dot(&a);
    let mut result = ata;
    // Add small value to diagonal to ensure positive definiteness
    for i in 0..n {
        result[[i, i]] += 0.1;
    }
    result
}

/// Generate test data similar to the iris dataset structure
/// Returns a 150×4 matrix with 3 groups of 50 samples each
pub fn test_iris_like_data() -> (Matrix, Vector) {
    let mut data = Matrix::zeros((150, 4));
    let mut labels = Vector::zeros(150);

    // Generate 3 groups with different means
    let group_means = [
        [5.0, 3.5, 1.4, 0.2],  // Group 0
        [5.9, 2.8, 4.3, 1.3],  // Group 1
        [6.5, 3.0, 5.5, 2.0],  // Group 2
    ];

    for (group_idx, means) in group_means.iter().enumerate() {
        let start = group_idx * 50;
        let end = start + 50;

        for i in start..end {
            for j in 0..4 {
                // Add some noise to the mean
                let noise = ((i + j) as f64 * 0.1).sin() * 0.5;
                data[[i, j]] = means[j] + noise;
            }
            labels[i] = group_idx as f64;
        }
    }

    (data, labels)
}

/// Generate a low-rank matrix for testing SVD
/// Creates a matrix of rank r embedded in m×n space
pub fn test_low_rank_matrix(m: usize, n: usize, r: usize) -> Matrix {
    assert!(r <= m.min(n), "Rank must be <= min(m, n)");

    // Generate U (m×r) and V (n×r) with orthonormal columns
    let u = qr_orthogonalize(&test_matrix(m, r));
    let v = qr_orthogonalize(&test_matrix(n, r));

    // Generate singular values
    let s = Array1::from_iter((0..r).map(|i| (r - i) as f64));

    // Construct the low-rank matrix
    let mut result = Matrix::zeros((m, n));
    for i in 0..r {
        let ui = u.slice(s![.., i]);
        let vi = v.slice(s![.., i]);
        result = result + s[i] * &ui.insert_axis(ndarray::Axis(1)).dot(&vi.insert_axis(ndarray::Axis(0)));
    }

    result
}

/// Simple QR orthogonalization for testing (not optimized)
fn qr_orthogonalize(a: &Matrix) -> Matrix {
    let (m, n) = a.dim();
    let mut q = a.clone();

    for j in 0..n {
        // Normalize column j
        let mut col_j = q.slice_mut(s![.., j]);
        let norm = col_j.dot(&col_j).sqrt();
        if norm > 1e-10 {
            col_j /= norm;
        }

        // Orthogonalize subsequent columns against column j
        for k in (j + 1)..n {
            let dot_jk = q.slice(s![.., j]).dot(&q.slice(s![.., k]));
            let mut col_k = q.slice_mut(s![.., k]);
            col_k.scaled_add(-dot_jk, &q.slice(s![.., j]));
        }
    }

    q
}

/// Assert that two matrices are approximately equal
pub fn assert_matrix_approx_eq(a: &Matrix, b: &Matrix, epsilon: f64) {
    assert_eq!(a.shape(), b.shape(), "Matrix shapes don't match");

    for i in 0..a.nrows() {
        for j in 0..a.ncols() {
            assert!(
                a[[i, j]].abs_diff_eq(&b[[i, j]], epsilon),
                "Matrices differ at position [{}, {}]: {} vs {} (tolerance: {})",
                i, j, a[[i, j]], b[[i, j]], epsilon
            );
        }
    }
}

/// Assert that two vectors are approximately equal
pub fn assert_vector_approx_eq(a: &Vector, b: &Vector, epsilon: f64) {
    assert_eq!(a.len(), b.len(), "Vector lengths don't match");

    for i in 0..a.len() {
        assert!(
            a[i].abs_diff_eq(&b[i], epsilon),
            "Vectors differ at position [{}]: {} vs {} (tolerance: {})",
            i, a[i], b[i], epsilon
        );
    }
}

/// Assert that a matrix is approximately symmetric
pub fn assert_matrix_symmetric(a: &Matrix, epsilon: f64) {
    assert_eq!(a.nrows(), a.ncols(), "Matrix must be square");

    for i in 0..a.nrows() {
        for j in i+1..a.ncols() {
            assert!(
                a[[i, j]].abs_diff_eq(&a[[j, i]], epsilon),
                "Matrix not symmetric at positions [{}, {}] and [{}, {}]: {} vs {}",
                i, j, j, i, a[[i, j]], a[[j, i]]
            );
        }
    }
}

/// Generate random data for benchmarking (requires rand feature)
#[cfg(feature = "rand")]
pub fn random_data(m: usize, n: usize) -> Matrix {
    use rand::distributions::{Distribution, StandardNormal};
    use rand::thread_rng;

    let mut rng = thread_rng();
    Array2::from_shape_fn((m, n), |_| StandardNormal.sample(&mut rng))
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_test_matrix() {
        let m = test_matrix(3, 4);
        assert_eq!(m.shape(), &[3, 4]);
        assert_eq!(m[[0, 0]], 1.0);
        assert_eq!(m[[0, 3]], 4.0);
        assert_eq!(m[[2, 3]], 12.0);
    }

    #[test]
    fn test_symmetric_positive_definite() {
        let m = test_symmetric_positive_definite(4);
        assert_matrix_symmetric(&m, 1e-10);

        // Check positive definiteness by ensuring all eigenvalues would be positive
        // (actual eigenvalue computation would require ndarray-linalg)
    }

    #[test]
    fn test_iris_like_data() {
        let (data, labels) = test_iris_like_data();
        assert_eq!(data.shape(), &[150, 4]);
        assert_eq!(labels.len(), 150);

        // Check that we have 3 groups
        assert_eq!(labels.slice(s![0..50]).iter().all(|&x| x == 0.0), true);
        assert_eq!(labels.slice(s![50..100]).iter().all(|&x| x == 1.0), true);
        assert_eq!(labels.slice(s![100..150]).iter().all(|&x| x == 2.0), true);
    }

    #[test]
    fn test_low_rank_matrix() {
        let m = test_low_rank_matrix(10, 8, 3);
        assert_eq!(m.shape(), &[10, 8]);
        // The matrix should have rank 3, but we can't easily verify without SVD
    }

    #[test]
    fn test_assert_matrix_approx_eq() {
        let a = test_matrix(3, 3);
        let b = a.clone();
        assert_matrix_approx_eq(&a, &b, 1e-10);

        let mut c = a.clone();
        c[[0, 0]] += 1e-8;
        assert_matrix_approx_eq(&a, &c, 1e-7);
    }

    #[test]
    #[should_panic(expected = "Matrices differ")]
    fn test_assert_matrix_approx_eq_fail() {
        let a = test_matrix(3, 3);
        let mut b = a.clone();
        b[[0, 0]] += 1.0;
        assert_matrix_approx_eq(&a, &b, 1e-10);
    }
}

